1	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	type Step = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
4	
5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_SURCHARGE = 0.1;
7	const CURSE_SURCHARGE = 0.5;
8	const COMPONENT_BLOCK_SIZE = 3;
9	const COMPONENT_BLOCK_PRICE = 60;
10	
11	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
12	  sword: 100,
13	  amulet: 60,
14	  staff: 80,
15	  potion: 40,
16	  rune: 25,
17	  moonstone: 25,
18	};
19	
20	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
21	
22	const basePremiumOf = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type];
23	
24	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
25	
26	const priceForComponentGroup = (type: string, count: number): number =>
27	  count === COMPONENT_BLOCK_SIZE
28	    ? COMPONENT_BLOCK_PRICE
29	    : count * BASE_PREMIUM_BY_TYPE[type];
30	
31	const countByType = (items: Item[]): Map<string, number> => {
32	  const counts = new Map<string, number>();
33	  for (const item of items) {
34	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
35	  }
36	  return counts;
37	};
38	
39	const sumBasePremiumsFor = (items: Item[]): number => {
40	  const mainItemsTotal = items
41	    .filter((item) => !isComponent(item))
42	    .reduce((sum, item) => sum + basePremiumOf(item), 0);
43	
44	  const componentsTotal = Array.from(countByType(items.filter(isComponent)))
45	    .reduce((sum, [type, count]) => sum + priceForComponentGroup(type, count), 0);
46	
47	  return mainItemsTotal + componentsTotal;
48	};
49	
50	const itemSurchargesFor = (items: Item[]): number =>
51	  items.reduce((sum, item) => sum + (item.cursed ? basePremiumOf(item) * CURSE_SURCHARGE : 0), 0);
52	
53	const computePremium = (items: Item[]): number => {
54	  const policyBase = sumBasePremiumsFor(items);
55	  const itemSurcharges = itemSurchargesFor(items);
56	  const firstInsurance = policyBase * FIRST_INSURANCE_SURCHARGE;
57	  return policyBase + itemSurcharges + firstInsurance + PROCESSING_FEE;
58	};
59	
60	// Rounds up to the nearest whole gold piece, in MHPCO's favor.
61	// Cleans float noise (e.g. 66.00000000000001) before ceiling.
62	const roundUpToGold = (amount: number): number =>
63	  Math.ceil(Math.round(amount * 1e6) / 1e6);
64	
65	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
66	  const results = scenario.steps.map((step) => ({
67	    premium: roundUpToGold(computePremium(step.items)),
68	  }));
69	  return { results };
70	};
